Java<pre><code>class Solution {

    public boolean containsDuplicate(int[] nums) {
        Set&lt;Integer&gt; uniques = new HashSet&lt;&gt;();
        for (int i = 0; i &lt; nums.length; i++) {
            if (uniques.contains(nums[i])) {
                return true;
            }
            uniques.add(nums[i]);
        }
        return false;
    }
}
