Java<pre><code>class Solution {

    public int[] twoSum(int[] nums, int target) {
        HashMap&lt;Integer, Integer&gt; prevMap = new HashMap&lt;&gt;();

        for (int i = 0; i &lt; nums.length; i++) {
            int num = nums[i];
            int diff = target - num;

            if (prevMap.containsKey(diff)) {
                return new int[] { prevMap.get(diff), i };
            }

            prevMap.put(num, i);
        }

        return new int[] {};
    }
}
