Java<pre><code>class Solution1 {

    /**
     * Time Complexity: O(nlog(k))
     * Space Complexity: O(n)
     */
    public int[] topKFrequent(int[] nums, int k) {
        int[] arr = new int[k];
        HashMap&lt;Integer, Integer&gt; map = new HashMap&lt;&gt;();
        for (int num : nums) map.put(num, map.getOrDefault(num, 0) + 1);
        PriorityQueue&lt;Map.Entry&lt;Integer, Integer&gt;&gt; pq = new PriorityQueue&lt;&gt;(
                (a, b) -&gt;
            a.getValue() - b.getValue()
        );
        for (Map.Entry&lt;Integer, Integer&gt; it : map.entrySet()) {
            pq.add(it);
            if (pq.size() &gt; k) pq.poll();
        }
        int i = k;
        while (!pq.isEmpty()) {
            arr[--i] = pq.poll().getKey();
        }
        return arr;
    }
}

class Solution2 {

    /**
     * Time Complexity: O(n)
     * Space Complexity: O(n)
     */
    public int[] topKFrequent(int[] numbers, int k) {
        HashMap&lt;Integer, Integer&gt; map = new HashMap&lt;&gt;();
        for (int number : numbers) map.put(
            number,
            map.getOrDefault(number, 0) + 1
        );

        int size = map.size();
        int[] keys = new int[size];
        int i = 0;
        for (int key : map.keySet()) keys[i++] = key;

        select(keys, map, 0, size - 1, size - k);
        return Arrays.copyOfRange(keys, size - k, size);
    }

    // Modified implementation of Hoare's selection algorithm:

    private void select(
        int[] keys,
        Map&lt;Integer, Integer&gt; map,
        int left,
        int right,
        int kSmallest
    ) {
        while (left != right) {
            int pivot = partition(keys, map, left, right, (left + right) / 2);

            if (kSmallest == pivot) return;

            if (kSmallest &lt; pivot) right = pivot - 1; else left = pivot + 1;
        }
    }

    private int partition(
        int[] keys,
        Map&lt;Integer, Integer&gt; map,
        int left,
        int right,
        int pivot
    ) {
        int pivotValue = map.get(keys[pivot]);
        swap(keys, pivot, right);
        int index = left;

        for (int i = left; i &lt;= right; i++) if (map.get(keys[i]) &lt; pivotValue) {
            swap(keys, i, index);
            index++;
        }
        swap(keys, right, index);
        return index;
    }

    private void swap(int[] array, int i1, int i2) {
        int temp = array[i1];
        array[i1] = array[i2];
        array[i2] = temp;
    }
}
class Solution3 {
     /**
     * Time Complexity: O(n)
     * Space Complexity: O(n)
     */
     public int[] topKFrequent(int[] nums, int k) {
        Map&lt;Integer, Integer&gt; count = new HashMap&lt;&gt;();
        List&lt;Integer&gt; bucket[] = new ArrayList[nums.length + 1];                

        for (int num : nums)
            count.merge(num, 1, Integer::sum);

        for (int key : count.keySet()){
            int freq = count.get(key);
            if (bucket[freq] == null)
                bucket[freq] = new ArrayList&lt;&gt;();
            bucket[freq].add(key);
        }

        int index = 0;
        int[] res = new int[k];
        for (int i = nums.length; i &gt;= 0; i--)
            if (bucket[i] != null)
                for (int val : bucket[i]){
                    res[index++] = val;
                    if(index == k)
                        return res;
                }
        return res;
    }
