Student.java<pre><code>package com.springjdbc.entities;

public class Student {
 private int Id;
 private String name;
 private String city;
public Student() {
    super();
    // TODO Auto-generated constructor stub
}
public Student(int id, String name, String city) {
    super();
    Id = id;
    this.name = name;
    this.city = city;
}
public int getId() {
    return Id;
}
public void setId(int id) {
    Id = id;
}
public String getName() {
    return name;
}
public void setName(String name) {
    this.name = name;
}
public String getCity() {
    return city;
}
public void setCity(String city) {
    this.city = city;
}
@Override
public String toString() {
    StringBuilder builder = new StringBuilder();
    builder.append("Student [Id=");
    builder.append(Id);
    builder.append(", name=");
    builder.append(name);
    builder.append(", city=");
    builder.append(city);
    builder.append("]");
    return builder.toString();
}

}
</code></pre>

